:root {
  --bg: #0f1418;
  --panel: #1a2129;
  --border: #2a343d;
  --text: #e6edf3;
  --muted: #8b98a5;
  --accent: #3fb950;
  --accent-2: #58a6ff;
  --danger: #f85149;
  --warn: #d29922;
}

* {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  padding: 0;
  background: var(--bg);
  color: var(--text);
  font-family: system-ui, -apple-system, "Segoe UI", Roboto, sans-serif;
  font-size: 15px;
  line-height: 1.5;
}

a {
  color: var(--accent-2);
  text-decoration: none;
}
a:hover {
  text-decoration: underline;
}

.container {
  max-width: 960px;
  margin: 0 auto;
  padding: 24px 16px 64px;
}

nav.topbar {
  background: var(--panel);
  border-bottom: 1px solid var(--border);
  padding: 12px 16px;
  display: flex;
  gap: 16px;
  align-items: center;
  flex-wrap: wrap;
}
nav.topbar .brand {
  font-weight: 700;
  color: var(--text);
}

.panel {
  background: var(--panel);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 16px 20px;
  margin-bottom: 16px;
}

.muted {
  color: var(--muted);
}

label {
  display: block;
  margin: 10px 0 4px;
  font-size: 13px;
  color: var(--muted);
}
input,
select {
  width: 100%;
  padding: 8px 10px;
  background: var(--bg);
  border: 1px solid var(--border);
  border-radius: 6px;
  color: var(--text);
  font-size: 14px;
}

button,
.btn {
  display: inline-block;
  padding: 8px 14px;
  background: var(--accent);
  color: #06210d;
  border: none;
  border-radius: 6px;
  font-weight: 600;
  cursor: pointer;
  font-size: 14px;
}
button.secondary {
  background: transparent;
  color: var(--text);
  border: 1px solid var(--border);
}
button.danger {
  background: var(--danger);
  color: #2a0606;
}

table {
  width: 100%;
  border-collapse: collapse;
  font-size: 13px;
}
th,
td {
  text-align: left;
  padding: 6px 8px;
  border-bottom: 1px solid var(--border);
}
th {
  color: var(--muted);
  font-weight: 600;
}

.badge {
  display: inline-block;
  padding: 2px 8px;
  border-radius: 999px;
  font-size: 12px;
  font-weight: 600;
}
.badge.on {
  background: rgba(63, 185, 80, 0.15);
  color: var(--accent);
}
.badge.off {
  background: rgba(139, 152, 165, 0.15);
  color: var(--muted);
}

