import { NextResponse } from "next/server";
import path from "node:path";
import { spawn } from "node:child_process";
import { logEvent } from "@/lib/db";
import { optionalEnv } from "@/lib/env";

export const runtime = "nodejs";
export const dynamic = "force-dynamic";

// POST /api/run-now — manually trigger brain.py (which decides duration via fuzzy
// and calls /api/run). Fire-and-forget: returns 202 immediately, logs the result
// when the brain process exits. Used by the UI "Run now" button.
export async function POST() {
  const repoRoot = path.resolve(process.cwd(), "..");
  const brainDir = path.join(repoRoot, "brain");
  const pythonBin = optionalEnv("PYTHON_BIN", "python");

  try {
    const child = spawn(pythonBin, ["brain.py", "manual"], {
      cwd: brainDir,
      env: process.env,
    });

    let out = "";
    child.stdout.on("data", (d) => (out += d.toString()));
    child.stderr.on("data", (d) => (out += d.toString()));
    child.on("error", (err) =>
      logEvent("error", "run_now_spawn_failed", { error: String(err), pythonBin })
    );
    child.on("close", (code) =>
      logEvent(code === 0 ? "info" : "error", "run_now_brain_exit", {
        code,
        output: out.slice(-2000),
      })
    );

    logEvent("info", "run_now_triggered", { pythonBin });
    return NextResponse.json({ triggered: true }, { status: 202 });
  } catch (err) {
    logEvent("error", "run_now_failed", { error: String(err) });
    return NextResponse.json({ error: String(err) }, { status: 500 });
  }
}

