// Telegram notification helper (server-only). Reads bot token + chat id from the
// `settings` table. If either is empty it falls back to LOG-ONLY (no network call)
// so the system is safe to run and test without a real bot. Notifications must
// NEVER throw into the control flow — failures are caught and logged.
import { getSetting, logEvent, type EventLevel } from "./db";

const EMOJI: Record<EventLevel, string> = {
  info: "ℹ️",
  warn: "⚠️",
  error: "🚨",
};

export interface TelegramResult {
  sent: boolean;
  reason?: string;
}

export async function sendTelegram(
  level: EventLevel,
  message: string
): Promise<TelegramResult> {
  const token = getSetting("telegram_bot_token");
  const chatId = getSetting("telegram_chat_id");
  const text = `${EMOJI[level]} ${message}`;

  if (!token || !chatId) {
    // Log-only mode — record the intended notification for audit.
    logEvent("info", "telegram_skipped_no_config", { level, message });
    console.log(`[telegram:log-only] ${text}`);
    return { sent: false, reason: "no_config" };
  }

  try {
    const res = await fetch(
      `https://api.telegram.org/bot${token}/sendMessage`,
      {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ chat_id: chatId, text }),
        // Don't let a slow/hanging Telegram call stall irrigation control.
        signal: AbortSignal.timeout(10_000),
      }
    );
    if (!res.ok) {
      const body = await res.text().catch(() => "");
      logEvent("warn", "telegram_failed", { status: res.status, body });
      return { sent: false, reason: `http_${res.status}` };
    }
    logEvent("info", "telegram_sent", { level, message });
    return { sent: true };
  } catch (err) {
    logEvent("warn", "telegram_failed", { error: String(err) });
    return { sent: false, reason: "exception" };
  }
}

