import { createServer } from "@/lib/supabase/server";
import { notFound } from "next/navigation";
import AnimatedDeviceDetailPage from "@/components/AnimatedDeviceDetailPage";

export type SensorConfig = {
    id: string;
    sensor_key: string;
    label: string;
    unit: string | null;
    color: string;
    calibration_a: number;
    calibration_b: number;
};

export type DeviceDetails = {
    id: string;
    name: string;
    offline_threshold_seconds: number;
    device_sensor_configs: SensorConfig[];
};

async function getDeviceData(deviceId: string) {
  const supabase = await createServer();

  const { data: device, error: deviceError } = await supabase
    .from('devices')
    .select(`
        id, 
        name, 
        offline_threshold_seconds,
        device_sensor_configs ( id, sensor_key, label, unit, color, calibration_a, calibration_b )
    `)
    .eq('id', deviceId)
    .single();

  if (deviceError || !device) {
    notFound();
  }

  // Get sensor alias rules
  const { data: sensorRules, error: rulesError } = await supabase
    .from('sensor_alias_rules')
    .select('sensor_key, rules')
    .eq('device_id', deviceId);

  const { data: initialData, error: initialDataError } = await supabase
    .from('telemetry_data')
    .select('*')
    .eq('device_id', deviceId)
    .order('created_at', { ascending: false })
    .limit(50);

  if (initialDataError) {
  }

  // Create rules map
  const rulesMap: Record<string, any[]> = {};
  if (sensorRules) {
    sensorRules.forEach(rule => {
      rulesMap[rule.sensor_key.toLowerCase()] = rule.rules || [];
    });
  }

  return { 
    device: device as DeviceDetails, 
    initialData: initialData || [],
    sensorRules: rulesMap
  };
}

export default async function DeviceDetailPage({ 
  params 
}: { 
  params: Promise<{ deviceId: string }> 
}) {
  const { deviceId } = await params;
  const { device, initialData, sensorRules } = await getDeviceData(deviceId);

  return (
    <AnimatedDeviceDetailPage 
      device={device} 
      initialData={initialData}
      sensorRules={sensorRules}
    />
  );
}

