  }
  // Soil channels: dynamic multi-select (checkboxes) -> comma-joined list.
  const soil = formData
    .getAll("soil_channels")
    .map((c) => String(c))
    .filter(Boolean);
  setSetting("soil_channels", soil.join(","));
  revalidatePath("/settings");
}

