"use server";

import { revalidatePath } from "next/cache";
import { setSetting } from "@/lib/db";

// Keys editable from the Settings UI. eWeLink creds are intentionally NOT here —
// they live only in .env. (Local const — a "use server" file may only EXPORT
// async functions.)
const SETTING_KEYS = [
  "agrihub_base_url",
  "agrihub_weather_apikey",
  "agrihub_soil_apikey",
  "telegram_bot_token",
  "telegram_chat_id",
  "pump_delay_on_seconds",
  "pump_delay_off_seconds",
  "safety_max_minutes",
] as const;

export async function updateSettings(formData: FormData) {
  for (const key of SETTING_KEYS) {
    const v = formData.get(key);
    if (v !== null) setSetting(key, String(v).trim());
  }
  revalidatePath("/settings");
}

