import { getDb } from "@/lib/db";
import { updateSettings } from "./actions";

export const dynamic = "force-dynamic";

function useSettings(): Record<string, string> {
  const rows = getDb().prepare("SELECT key, value FROM settings").all() as {
    key: string;
    value: string;
  }[];
  return Object.fromEntries(rows.map((r) => [r.key, r.value ?? ""]));
}

function Field({
  name,
  label,
  value,
  type = "text",
  hint,
}: {
  name: string;
  label: string;
  value: string;
  type?: string;
  hint?: string;
}) {
  return (
    <div>
      <label htmlFor={name}>{label}</label>
      <input id={name} name={name} type={type} defaultValue={value} />
      {hint && (
        <p className="muted" style={{ fontSize: 12, marginTop: 2 }}>
          {hint}
        </p>
      )}
    </div>
  );
}

export default function SettingsPage() {
  const s = useSettings();

  return (
    <>
      <form action={updateSettings} className="panel">
      <h1>Settings</h1>

      <div className="panel" style={{ background: "var(--bg)" }}>
        <h3>agrihub.id</h3>
        <Field name="agrihub_base_url" label="Base URL" value={s.agrihub_base_url ?? ""} hint="mis. https://agrihub.id" />
        <Field name="agrihub_weather_apikey" label="Weather API key" value={s.agrihub_weather_apikey ?? ""} />
        <Field name="agrihub_soil_apikey" label="Soil API key" value={s.agrihub_soil_apikey ?? ""} />
      </div>

      <div className="panel" style={{ background: "var(--bg)" }}>
        <h3>Telegram</h3>
        <Field name="telegram_bot_token" label="Bot token" value={s.telegram_bot_token ?? ""} hint="Isi token → bot aktif menerima /subscribe & broadcast notif. Kosong = log-only." />
        <Field name="telegram_chat_id" label="Chat ID admin (opsional)" value={s.telegram_chat_id ?? ""} hint="Opsional — chat ini selalu menerima notif. User lain cukup kirim /subscribe ke bot." />
      </div>

      <div className="panel" style={{ background: "var(--bg)" }}>
        <h3>Timing &amp; safety</h3>
        <Field name="pump_delay_on_seconds" label="Pump delay ON (detik)" value={s.pump_delay_on_seconds ?? "7"} type="number" hint="Jeda valve→pompa (default 7)." />
        <Field name="pump_delay_off_seconds" label="Pump delay OFF (detik)" value={s.pump_delay_off_seconds ?? "0"} type="number" hint="Jeda pompa→valve saat mati (default 0)." />
        <Field name="safety_max_minutes" label="Safety cutoff (menit)" value={s.safety_max_minutes ?? "60"} type="number" hint="Cutoff absolut watchdog (default 60)." />
      </div>

      <button type="submit">Simpan settings</button>
      </form>

      <Subscribers />
    </>
  );
}

interface SubRow {
  chat_id: string;
  name: string | null;
  username: string | null;
  active: number;
  subscribed_at: string;
}

function Subscribers() {
  const subs = getDb()
    .prepare(
      "SELECT chat_id, name, username, active, subscribed_at FROM subscribers ORDER BY active DESC, subscribed_at DESC"
    )
    .all() as SubRow[];
  const activeCount = subs.filter((s) => s.active).length;

  return (
    <div className="panel">
      <h2>Subscriber Telegram ({activeCount} aktif)</h2>
      <p className="muted">
        Notifikasi di-broadcast ke semua subscriber aktif. User berlangganan dengan
        mengirim <code>/subscribe</code> ke bot (perlu bot token terisi di atas).
      </p>
      {subs.length === 0 ? (
        <p className="muted">Belum ada subscriber.</p>
      ) : (
        <table>
          <thead>
            <tr>
              <th>Nama</th>
              <th>Username</th>
              <th>chat_id</th>
              <th>Status</th>
              <th>Sejak (UTC)</th>
            </tr>
          </thead>
          <tbody>
            {subs.map((sub) => (
              <tr key={sub.chat_id}>
                <td>{sub.name || "—"}</td>
                <td>{sub.username ? `@${sub.username}` : "—"}</td>
                <td>{sub.chat_id}</td>
                <td>
                  <span className={`badge ${sub.active ? "on" : "off"}`}>
                    {sub.active ? "aktif" : "berhenti"}
                  </span>
                </td>
                <td>{sub.subscribed_at}</td>
              </tr>
            ))}
          </tbody>
        </table>
      )}
    </div>
  );
}

// Seed default data. Idempotent: existing rows are preserved (INSERT OR IGNORE /
// "only when empty"), so re-running never clobbers values you edited in the UI.
import crypto from "node:crypto";
import { loadEnv, openDb } from "./util.mjs";

loadEnv();
const db = openDb();

// --- Password hashing (scrypt) -----------------------------------------------
// Format kept identical to control-app/lib/auth.ts (M9): scrypt$<saltHex>$<hashHex>.
function hashPassword(password) {
  const salt = crypto.randomBytes(16);
  const hash = crypto.scryptSync(password, salt, 64);
  return `scrypt$${salt.toString("hex")}$${hash.toString("hex")}`;
}

// --- 1. Fuzzy config (defaults mirror the Python FuzzyConfig dataclass) -------
db.prepare(
  `INSERT OR IGNORE INTO fuzzy_config
     (id, sdmin, snmin, sdmax, swmin, snmax, swmax,
      elmin, emmin, elmax, ehmin, emmax, ehmax,
      os, om, ol, output_max)
   VALUES (1, 16, 20, 24, 25, 28, 30,
           0, 0.1, 0.25, 0.35, 0.6, 1.0,
           5, 15, 30, 60)`
).run();

// --- 2. Device config (2 valves on Device 1, 1 pump on Device 2) -------------
// device_id are placeholders — edit them from the UI once you know the real IDs.
const deviceCount = db.prepare("SELECT COUNT(*) c FROM device_config").get().c;
if (deviceCount === 0) {
  const ins = db.prepare(
    "INSERT INTO device_config (role, device_id, channel, label, enabled) VALUES (?,?,?,?,1)"
  );
  ins.run("valve", "DEVICE1_ID", 1, "Valve 1");
  ins.run("valve", "DEVICE1_ID", 2, "Valve 2");
  ins.run("pump", "DEVICE2_ID", 1, "Pompa");
}

// --- 3. Schedules (07:00 & 16:00 Asia/Jakarta) -------------------------------
const schedCount = db.prepare("SELECT COUNT(*) c FROM schedules").get().c;
if (schedCount === 0) {
  const ins = db.prepare(
    "INSERT INTO schedules (time, enabled, timezone) VALUES (?, 1, 'Asia/Jakarta')"
  );
  ins.run("07:00");
  ins.run("16:00");
}

// --- 4. Settings (single-value; secrets like eWeLink creds stay in .env) -----
const settingsDefaults = {
  pump_delay_on_seconds: "7",
  pump_delay_off_seconds: "0",
  safety_max_minutes: "60",
  agrihub_base_url: process.env.AGRIHUB_BASE_URL || "",
  agrihub_weather_apikey: process.env.AGRIHUB_WEATHER_APIKEY || "",
  agrihub_soil_apikey: process.env.AGRIHUB_SOIL_APIKEY || "",
  telegram_bot_token: process.env.TELEGRAM_BOT_TOKEN || "",
  telegram_chat_id: process.env.TELEGRAM_CHAT_ID || "",
};
const insSetting = db.prepare(
  "INSERT OR IGNORE INTO settings (key, value) VALUES (?, ?)"
);
for (const [k, v] of Object.entries(settingsDefaults)) insSetting.run(k, v);

// --- 5. Admin user -----------------------------------------------------------
const adminUser = process.env.ADMIN_USERNAME || "admin";
const adminPass = process.env.ADMIN_PASSWORD || "";
let userMsg;
if (!adminPass) {
  userMsg = `⚠️  ADMIN_PASSWORD kosong di .env — user admin TIDAK dibuat. Isi ADMIN_PASSWORD lalu jalankan ulang seed.`;
} else {
  const existing = db
    .prepare("SELECT 1 FROM users WHERE username = ?")
    .get(adminUser);
  if (existing) {
    userMsg = `ℹ️  User '${adminUser}' sudah ada — dilewati.`;
  } else {
    db.prepare(
      "INSERT INTO users (username, password_hash) VALUES (?, ?)"
    ).run(adminUser, hashPassword(adminPass));
    userMsg = `✅ User admin '${adminUser}' dibuat.`;
  }
}

console.log("✅ Seed selesai.");
console.log(`   fuzzy_config: 1 baris`);
console.log(`   device_config: ${db.prepare("SELECT COUNT(*) c FROM device_config").get().c} baris`);
console.log(`   schedules: ${db.prepare("SELECT time FROM schedules ORDER BY time").all().map((r) => r.time).join(", ")}`);
console.log(`   settings: ${db.prepare("SELECT COUNT(*) c FROM settings").get().c} key`);
console.log(`   ${userMsg}`);
db.close();

